from dataclasses import dataclass from typing import List, Dict, Any, Optional, Set import json from datetime import datetime
@dataclass class EvaluationResult: question: str answer: str context: List[str] ground_truth: Optional[str] retrieval_metrics: Dict[str, float] generation_metrics: Dict[str, float] timestamp: str
class RAGEvaluator: """Complete RAG evaluation pipeline."""
def __init__(self, rag_pipeline, model: str = "gpt-4o"): self.rag = rag_pipeline self.model = model self.results: List[EvaluationResult] = []
def evaluate_single( self, question: str, ground_truth: Optional[str] = None, relevant_doc_ids: Optional[Set[str]] = None ) -> EvaluationResult: """Evaluate single question.""" # Get RAG response response = self.rag.query(question)
# Extract components answer = response["answer"] contexts = [s["content"] for s in response["sources"]] retrieved_ids = [s["metadata"].get("id") for s in response["sources"]]
# Retrieval metrics (from rag-eval-metrics) from rag_eval_metrics import precision_at_k, recall_at_k, mean_reciprocal_rank, hit_rate
retrieval_metrics = {} if relevant_doc_ids: retrieval_metrics["precision@5"] = precision_at_k(retrieved_ids, relevant_doc_ids, 5) retrieval_metrics["recall@5"] = recall_at_k(retrieved_ids, relevant_doc_ids, 5) retrieval_metrics["mrr"] = mean_reciprocal_rank(retrieved_ids, relevant_doc_ids) retrieval_metrics["hit_rate"] = hit_rate(retrieved_ids, relevant_doc_ids)
# Generation metrics from rag_eval_metrics import evaluate_faithfulness, evaluate_relevance, evaluate_context_relevance
context_combined = "\n\n".join(contexts) faithfulness_result = evaluate_faithfulness(answer, context_combined, self.model) relevance_result = evaluate_relevance(answer, question, self.model) context_result = evaluate_context_relevance(context_combined, question, self.model)
generation_metrics = { "faithfulness": faithfulness_result.get("score", 0), "answer_relevance": relevance_result.get("score", 0), "context_relevance": context_result.get("score", 0) }
result = EvaluationResult( question=question, answer=answer, context=contexts, ground_truth=ground_truth, retrieval_metrics=retrieval_metrics, generation_metrics=generation_metrics, timestamp=datetime.now().isoformat() )
self.results.append(result) return result
def evaluate_batch( self, test_set: List[Dict[str, Any]] ) -> Dict[str, float]: """Evaluate batch of questions and compute aggregate metrics.""" for item in test_set: self.evaluate_single( question=item["question"], ground_truth=item.get("answer"), relevant_doc_ids=item.get("relevant_docs") )
return self.aggregate_metrics()
def aggregate_metrics(self) -> Dict[str, float]: """Compute aggregate metrics across all evaluations.""" if not self.results: return {}
metrics = { "avg_faithfulness": 0, "avg_answer_relevance": 0, "avg_context_relevance": 0, "avg_precision@5": 0, "avg_recall@5": 0, "avg_mrr": 0, "total_evaluated": len(self.results) }
for result in self.results: metrics["avg_faithfulness"] += result.generation_metrics.get("faithfulness", 0) metrics["avg_answer_relevance"] += result.generation_metrics.get("answer_relevance", 0) metrics["avg_context_relevance"] += result.generation_metrics.get("context_relevance", 0) metrics["avg_precision@5"] += result.retrieval_metrics.get("precision@5", 0) metrics["avg_recall@5"] += result.retrieval_metrics.get("recall@5", 0) metrics["avg_mrr"] += result.retrieval_metrics.get("mrr", 0)
n = len(self.results) for key in metrics: if key.startswith("avg_"): metrics[key] /= n
return metrics
def export_results(self, filepath: str): """Export results to JSON.""" data = [ { "question": r.question, "answer": r.answer, "ground_truth": r.ground_truth, "retrieval_metrics": r.retrieval_metrics, "generation_metrics": r.generation_metrics, "timestamp": r.timestamp } for r in self.results ]
with open(filepath, "w") as f: json.dump(data, f, indent=2)
# Usage # evaluator = RAGEvaluator(rag_pipeline) # results = evaluator.evaluate_batch(test_set) # evaluator.export_results("evaluation_results.json")
